UPDATE public.questions SET
  stimulus_text = 'In the following excerpt from an essay on the evolution of music, the author discusses the relationship between music and technology. 

"Technology has always been a driving force in the evolution of music, but it has not always been a benevolent one. The advent of recording technology in the late nineteenth century, for example, allowed for the mass production and distribution of music, but it also led to a decline in the quality of live music performance. The rise of electronic music in the twentieth century, with its reliance on synthesizers and computers, furthered the trend toward a more artificial sound. This technological trend has reached its apotheosis in the present day, with the proliferation of digital music streaming services that have rendered the traditional model of music consumption obsolete. The digital revolution, while it has democratized access to music and made it easier than ever to create and share it, has also created a culture of disposable music, in which songs are consumed quickly and then discarded, and the art of music making is increasingly marginalized."',
  question_text = 'The author''s main point about the relationship between music and technology is that',
  stimulus_type = NULL,
  options = '[{"id":"A","text":"technology has a positive impact on the evolution of music.","is_correct":false,"explanation":"Choice A is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"B","text":"technology has had a mixed impact on the evolution of music.","is_correct":true,"explanation":"Choice B matches the question''s requirement and is consistent with the passage''s central claim or supporting detail. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"C","text":"technology has had a negative impact on the evolution of music.","is_correct":false,"explanation":"Choice C is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"D","text":"technology has made music more accessible and democratic.","is_correct":false,"explanation":"Choice D is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."}]'::jsonb,
  correct_answer = 'B',
  explanation = 'The author acknowledges that technology has made music more accessible and democratic, but also points out that technology has also led to a decline in the quality of live performance and the rise of a more artificial sound. Therefore, the author''s main point is that technology has had a mixed impact on the evolution of music. The passage states that "In the following excerpt from an essay on the evolution of music, the author discusses the relationship between music an…", which is the textual anchor for eliminating weaker choices. Choice B is correct because it aligns with that evidence: technology has had a mixed impact on the evolution of music.. Each incorrect option either contradicts a explicit detail, imports information not present in the text, or answers a different question than the one asked.',
  source_metadata = COALESCE(source_metadata, '{}'::jsonb) || '{"section":"english","skill_id":"CID","domain_id":"information","opensat_index":883,"opensat_domain":"Information and Ideas","opensat_raw_id":"random_id_c4","opensat_difficulty":"Hard","english_content_v2":true,"english_content_upgraded_at":"2026-06-12T20:01:56.898Z","english_content_upgrade_method":"upgrade-english-content.mjs"}'::jsonb,
